import React from "react"
import { RiDoubleQuotesL, RiDoubleQuotesR } from "react-icons/ri"
import { useCMS } from "../../contexts/CMSContext"
import "./record.css"

const Page4NienKhoa: React.FC = () => {
  const { cmsData } = useCMS()
  const content = cmsData.pages.page4.nienKhoaContent

  if (!content) return null

  return (
    <section className="page4-nienkhoa-section">
      {content.blocks.map((block, index) => {
        /* ===== SCHEDULE BLOCK ===== */
        if (block.type === "schedule") {
          return (
            <div key={block.id} className="page4-nienkhoa-block">
              <div className="page4-nienkhoa-content">
                <h2 className="page4-nienkhoa-title" data-aos="fade-up">
                  {block.title}
                </h2>
                <div className="page4-nienkhoa-underline" />

                <div className="page4-nienkhoa-course">
                  <h3
                    className="page4-nienkhoa-course-title"
                    data-aos="fade-up"
                  >
                    {block.schedules.heading}
                  </h3>

                  <div
                    className="page4-nienkhoa-schedule"
                    data-aos="fade-up"
                  >
                    {block.schedules.items.map(item => (
                      <div key={item.id} className="page4-schedule-item">
                        <strong>{item.dayLabel}</strong>
                        <div className="page4-schedule-details">
                          {item.details.map((line, i) => (
                            <div key={i}>{line}</div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="page4-nienkhoa-image">
                <picture>
                  <source
                    media="(max-width: 768px)"
                    srcSet={block.imageMobile}
                  />
                  <img
                    src={block.imageDesktop}
                    alt={block.title}
                    data-aos="fade-up"
                  />
                </picture>
              </div>
            </div>
          )
        }

        /* ===== COURSE BLOCK ===== */
        if (block.type === "course") {
          return (
            <div key={block.id} className="page4-nienkhoa-block">
              <div className="page4-nienkhoa-content">
                <h2 className="page4-nienkhoa-title" data-aos="fade-up">
                  {block.title}
                </h2>
                <div className="page4-nienkhoa-underline" />

                {block.courses.map(course => (
                  <div
                    key={course.id}
                    className="page4-nienkhoa-course"
                  >
                    <h3
                      className="page4-nienkhoa-course-title2"
                      data-aos="fade-up"
                    >
                      {course.title} ›
                    </h3>
                    <p
                      className="page4-nienkhoa-paragraph"
                      data-aos="fade-up"
                    >
                      <RiDoubleQuotesL className="quote-left" />
                      {course.description}
                      <RiDoubleQuotesR className="quote-right" />
                    </p>
                  </div>
                ))}
              </div>

              <div className="page4-nienkhoa-image">
                <img
                  src={block.imageDesktop}
                  alt={block.title}
                  data-aos="fade-up"
                />
              </div>
            </div>
          )
        }

        return null
      })}
    </section>
  )
}

export default Page4NienKhoa
